const resp = $input.first().json;
const html = String(resp.data || resp.body || resp);
const headers = resp.headers || {};

// CSRF token del formulario de login
const match = html.match(/name="__RequestVerificationToken"[^>]*value="([^"]+)"|value="([^"]+)"[^>]*name="__RequestVerificationToken"/);
const csrfToken = match ? (match[1] || match[2] || '') : '';

// Cookie inicial de sesión (ASP.NET_SessionId o similar)
const raw = headers['set-cookie'] || [];
const list = Array.isArray(raw) ? raw : [raw];
const initialCookie = list.map(c => c.split(';')[0]).filter(Boolean).join('; ');

return [{ json: { csrfToken, initialCookie } }];

const resp  = $input.first().json;
const heads = resp.headers || {};

// Cookie de sesión post-login
const raw  = heads['set-cookie'] || [];
const list = Array.isArray(raw) ? raw : [raw];
const sessionCookie = list.map(c => c.split(';')[0]).filter(Boolean).join('; ');

// Bearer token (puede venir en header, body JSON o HTML)
let bearerToken = '';
if (heads['authorization']) {
  bearerToken = String(heads['authorization']).replace(/^Bearer\s+/i, '').trim();
}
if (!bearerToken) {
  try {
    const body = typeof resp.data === 'object' ? resp.data : JSON.parse(String(resp.data || '{}'));
    bearerToken = body?.token || body?.Token || body?.access_token || body?.bearerToken || '';
  } catch(_) {}
}
if (!bearerToken) {
  const m = String(resp.data || '').match(/[Bb]earer[:\s]+([A-Za-z0-9\-._~+\/]+=*)/);
  if (m) bearerToken = m[1];
}

const loginSuccess = !!(sessionCookie || bearerToken);
return [{ json: { sessionCookie, bearerToken, loginSuccess, statusCode: resp.statusCode || 0 } }];

