const { bearerToken, sessionCookie } = $input.first().json;
const today = new Date();
const dd = String(today.getDate()).padStart(2,'0');
const mm = String(today.getMonth()+1).padStart(2,'0');
const yyyy = today.getFullYear();
const toDate = `${dd}/${mm}/${yyyy}`;

const BASE_PARAMS = {
  PageSize:'100', CustomerType:'-1', StageId:'-1', Country:'all',
  FromDate:'01/01/2018', ToDate:toDate, CustomerProfileId:'-1',
  Search:'', CustomerSearchId:'0', SalesBy:'', ReportingUserId:'0',
  SortColumn:'CUST.InsertedOn', SortOrder:'DESC', BOApprovalStatus:'-1',
  RiskClassification:'-1', IsPEP:'-1', FromLastCallTime:'', ToLastCallTime:'',
  CampaignCode:'-1', SubCampaignCode:'-1', SubCampaign2Code:'-1',
  FunnelCode:'-1', SubsourceCode:'-1', FromLastEffectiveCallTime:'',
  ToLastEffectiveCallTime:'', IsEligible:'-1', Gender:'-1', Nationality:'-1',
  DateOfApprovalFromDate:'', DateOfApprovalToDate:'', RefferedBy:'-1',
  EducationLevel:'-1', EmployementStatus:'-1', ApprovedBy:'0', Potential:'-1',
  Source:'-1', Affiliate:'-1', RegistrationType:'-1', DeclinedType:'-1',
  JobTitle:'-1', GrossAnnualIncome:'-1', SourceOfFund:'-1', Proffesion:'-1',
  AnnualTurnOver:'-1', OutComeIds:'0', RetentionalStatusIds:'0',
  LastRetentionEffectiveCallFromDate:'', LastRetentionEffectiveCallToDate:'',
  Tags:'0', FirstDepositFromDate:'', FirstDepositToDate:'',
  LastDepositFromDate:'', LastDepositToDate:'', MinTotalDeposit:'',
  MaxTotalDeposit:'', MinTotalWithdraw:'', MaxTotalWithdraw:'',
};

const allLeads = [];
let pageNumber  = 1;
let hasMore     = true;

while (hasMore) {
  const params = new URLSearchParams({ ...BASE_PARAMS, PageNumber: String(pageNumber) });
  let resp;
  for (let attempt = 1; attempt <= 3; attempt++) {
    try {
      resp = await $helpers.httpRequest({
        method: 'POST',
        url: 'https://production-backoffice.monedadelmundo.com/Customer/DynamicCustomerGet',
        headers: {
          'Authorization': `Bearer ${bearerToken}`,
          'Cookie': sessionCookie,
          'X-Requested-With': 'XMLHttpRequest',
          'Isajax': 'true',
          'Content-Type': 'application/x-www-form-urlencoded; charset=UTF-8',
          'Origin': 'https://production-backoffice.monedadelmundo.com',
          'Referer': 'https://production-backoffice.monedadelmundo.com/Customer/ClientList',
        },
        body: params.toString(),
      });
      break;
    } catch (e) {
      if (attempt === 3) throw new Error(`Pág ${pageNumber} falló 3 veces: ${e.message}`);
      await new Promise(r => setTimeout(r, 5000 * attempt));
    }
  }

  // Detectar el array de leads (distintos CRMs usan distintas keys)
  let leads = [];
  if (Array.isArray(resp)) {
    leads = resp;
  } else if (resp && typeof resp === 'object') {
    leads = resp.data || resp.Data || resp.customers || resp.Customers ||
            resp.result || resp.Result || resp.items || resp.Items || [];
  }
  if (!Array.isArray(leads)) leads = [];

  allLeads.push(...leads);
  console.log(`Pág ${pageNumber}: ${leads.length} leads (total: ${allLeads.length})`);
  hasMore = leads.length === 100;
  pageNumber++;
}

if (!allLeads.length) return [{ json: { totalLeads: 0, leads: [] } }];
return allLeads.map(lead => ({ json: lead }));

const items = $input.all();
const isEmpty = items.length === 0 || (items.length === 1 && items[0].json?.totalLeads === 0);
return [{ json: { isEmpty, count: isEmpty ? 0 : items.length } }];

const seen = new Set();
const result = $input.all().filter(item => {
  const id = String(
    item.json?.CustomerId || item.json?.customerId ||
    item.json?.Id         || item.json?.id         || ''
  );
  if (!id || seen.has(id)) return false;
  seen.add(id);
  return true;
});
console.log(`Deduplicación: ${$input.all().length} → ${result.length} registros únicos`);
return result;

const count = $input.all().length;
console.log(`✅ ${count} leads guardados en Google Sheets — ${new Date().toISOString()}`);
return [{ json: { success: true, leadsProcessed: count, timestamp: new Date().toISOString() } }];
